#!/usr/bin/env python3"""Auto-reindex watcher for Medical Chatbot.Monitors the Data/ directory for changes and automatically triggers re-indexing."""import timeimport sysimport subprocessimport loggingfrom watchdog.observers import Observerfrom watchdog.events import FileSystemEventHandlerfrom pathlib import Pathlogging.basicConfig(    level=logging.INFO,    format='%(asctime)s - %(levelname)s - %(message)s')logger = logging.getLogger(__name__)class PDFChangeHandler(FileSystemEventHandler):    """Handler for PDF file changes."""    def __init__(self):        self.last_reindex = 0        self.reindex_cooldown = 60  # Wait 60 seconds before re-indexing again    def should_reindex(self):        """Check if enough time has passed since last re-index."""        current_time = time.time()        if current_time - self.last_reindex > self.reindex_cooldown:            self.last_reindex = current_time            return True        return False    def trigger_reindex(self, event_type, file_path):        """Trigger the re-indexing process."""        if not self.should_reindex():            logger.info(f"Skipping re-index (cooldown period). Event: {event_type} on {file_path}")            return        logger.info(f"PDF change detected: {event_type} on {file_path}")        logger.info("Triggering automatic re-indexing...")        try:            result = subprocess.run(                [sys.executable, 'store_index.py'],                capture_output=True,                text=True,                timeout=300            )            if result.returncode == 0:                logger.info("✓ Automatic re-indexing completed successfully")            else:                logger.error(f"✗ Re-indexing failed: {result.stderr}")        except subprocess.TimeoutExpired:            logger.error("✗ Re-indexing timed out (>5 minutes)")        except Exception as e:            logger.error(f"✗ Re-indexing error: {e}")    def on_created(self, event):        """Handle file creation events."""        if not event.is_directory and event.src_path.endswith('.pdf'):            self.trigger_reindex('created', event.src_path)    def on_deleted(self, event):        """Handle file deletion events."""        if not event.is_directory and event.src_path.endswith('.pdf'):            self.trigger_reindex('deleted', event.src_path)    def on_modified(self, event):        """Handle file modification events."""        if not event.is_directory and event.src_path.endswith('.pdf'):            self.trigger_reindex('modified', event.src_path)def start_watcher(data_dir='Data'):    """Start watching the data directory for changes."""    logger.info(f"Starting PDF file watcher for directory: {data_dir}")    logger.info(f"Cooldown between re-indexes: 60 seconds")    logger.info("Press Ctrl+C to stop")    logger.info("-" * 50)    # Ensure directory exists    Path(data_dir).mkdir(exist_ok=True)    event_handler = PDFChangeHandler()    observer = Observer()    observer.schedule(event_handler, data_dir, recursive=False)    observer.start()    try:        while True:            time.sleep(1)    except KeyboardInterrupt:        logger.info("Stopping watcher...")        observer.stop()    observer.join()    logger.info("Watcher stopped")if __name__ == '__main__':    data_directory = sys.argv[1] if len(sys.argv) > 1 else 'Data'    start_watcher(data_directory)
